(() => {
  const icons = {
    'lucide:alarm-clock': '⏰',
    'lucide:alert-circle': '!',
    'lucide:alert-triangle': '!',
    'lucide:arrow-left': '‹',
    'lucide:award': '🏅',
    'lucide:badge-check': '✓',
    'lucide:book-open-check': '✓',
    'lucide:calendar-clock': '⏱',
    'lucide:check': '✓',
    'lucide:check-circle': '✓',
    'lucide:check-circle-2': '✓',
    'lucide:clipboard-check': '✓',
    'lucide:clipboard-list': '▤',
    'lucide:clock': '⏱',
    'lucide:copy': '⧉',
    'lucide:download': '⇩',
    'lucide:edit-3': '✎',
    'lucide:file-search': '⌕',
    'lucide:file-text': '≡',
    'lucide:flag': '⚑',
    'lucide:graduation-cap': '🎓',
    'lucide:log-out': '↗',
    'lucide:menu': '☰',
    'lucide:message-square': '▢',
    'lucide:pencil': '✎',
    'lucide:phone-call': '☎',
    'lucide:phone-missed': '☎',
    'lucide:plus': '+',
    'lucide:plus-circle': '+',
    'lucide:rocket': '↗',
    'lucide:save': '✓',
    'lucide:search': '⌕',
    'lucide:smartphone': '▯',
    'lucide:sparkles': '✦',
    'lucide:trash-2': '×',
    'lucide:upload': '⇧',
    'lucide:user': '👤',
    'lucide:user-plus': '+',
    'lucide:users': '👥',
    'lucide:x': '×',
    'lucide:x-circle': '×'
  };

  class IconifyIcon extends HTMLElement {
    static get observedAttributes() {
      return ['icon', 'width'];
    }

    connectedCallback() {
      this.render();
    }

    attributeChangedCallback() {
      this.render();
    }

    render() {
      const icon = this.getAttribute('icon') || '';
      const width = this.getAttribute('width') || '16';
      this.textContent = icons[icon] || '•';
      this.style.display = 'inline-flex';
      this.style.alignItems = 'center';
      this.style.justifyContent = 'center';
      this.style.width = `${width}px`;
      this.style.minWidth = `${width}px`;
      this.style.height = `${width}px`;
      this.style.fontSize = `${Math.max(12, Number(width) || 16)}px`;
      this.style.lineHeight = '1';
      this.style.fontWeight = '700';
      this.style.verticalAlign = '-0.15em';
    }
  }

  if (!customElements.get('iconify-icon')) {
    customElements.define('iconify-icon', IconifyIcon);
  }
})();
